import gzip, json
with gzip.open('test/e2e/fixtures/recorded/chat-simple.opencode.json.gz') as f:
    data = json.load(f)
print('Top-level keys:', list(data.keys()))
interactions = data.get('interactions', [])
print(f'Total interactions: {len(interactions)}')

# Show REST endpoints
rest_endpoints = {}
for ix in interactions:
    if ix.get('kind') == 'rest':
        path = ix['path'].split('?')[0]
        key = f\"{ix['method']} {path}\"
        rest_endpoints[key] = rest_endpoints.get(key, 0) + 1
print('\nREST endpoints:')
for ep in sorted(rest_endpoints.keys()):
    print(f'  {ep}: {rest_endpoints[ep]}x')

# Show SSE event types
sse_types = {}
for ix in interactions:
    if ix.get('kind') == 'sse':
        t = ix['type']
        sse_types[t] = sse_types.get(t, 0) + 1
print(f'\nSSE event types:')
for t in sorted(sse_types.keys()):
    print(f'  {t}: {sse_types[t]}x')

# Show unique session IDs in SSE events
session_ids = set()
for ix in interactions:
    if ix.get('kind') == 'sse':
        props = ix.get('properties', {})
        sid = props.get('sessionID')
        if not sid:
            part = props.get('part', {})
            if isinstance(part, dict):
                sid = part.get('sessionID')
        if not sid:
            info = props.get('info', {})
            if isinstance(info, dict):
                sid = info.get('id') or info.get('sessionID')
        if sid:
            session_ids.add(sid)
print(f'\nSSE session IDs:')
for s in sorted(session_ids):
    print(f'  {s}')
"

